var e=JSON.parse(`[{"id":"L1_1","type":"subtitle","speaker":null,"text":{"KOREA":"AEGIS 8 PBLIT SECURITY SEQUENCE <color=#ffd34c>ACTIVATED</color>     \\nADC FACTOR <color=#ffd34c>ALPHA CONFIRMED</color>      \\nCCN No. AS002M0035-04: <color=#ffd34c>【부록-003】 영상 기록#2</color>      ","JPN":"AEGIS 8 PBLIT SECURITY SEQUENCE <color=#ffd34c>ACTIVATED</color>……\\nADC FACTOR <color=#ffd34c>ALPHA CONFIRMED</color>……\\nCCN No. AS002M0035-04：<color=#ffd34c>【付録-003】 映像記録#2</color>      ","ENG":"AEGIS 8 PBLIT SECURITY SEQUENCE <color=#ffd34c>ACTIVATED</color>     \\nADC FACTOR <color=#ffd34c>ALPHA CONFIRMED</color>      \\nCCN No. AS002M0035-04: <color=#ffd34c>【Appendix-003】 Video Record #2</color>      ","TWN":"AEGIS 8 PBLIT SECURITY SEQUENCE <color=#ffd34c>ACTIVATED</color>     \\nADC FACTOR <color=#ffd34c>ALPHA CONFIRMED</color>      \\nCCN No. AS002M0035-04: <color=#ffd34c>【附錄-003】 影像記錄#2</color>","THA":"กระบวนการตรวจสอบประวัติเพื่อความปลอดภัย AEGIS 8 PBLIT: <color=#ffd34c>เปิดทำงาน</color>     \\nADC แฟกเตอร์: <color=#ffd34c>ยืนยันในระดับอัลฟ่า</color>     \\nCCN หมายเลข AS002M0035-04: <color=#ffd34c>[เอกสารแนบท้าย-003] บันทึกวิดีโอ #2</color>","VTN":"TRÌNH TỰ AN NINH AEGIS 8 PBLIT <color=#ffd34c>ĐÃ KÍCH HOẠT</color>     \\nTHÔNG SỐ ADC <color=#ffd34c>XÁC NHẬN ALPHA </color>     \\nCCN Số. AS002M0035-04: <color=#ffd34c>[Phụ Lục-003] Hồ Sơ Video #2</color>","SCN":"AEGIS 8 PBLIT安全序列: <color=#ffd34c>激活</color>\\nADC 因素: <color=#ffd34c>阿尔法确认</color>      \\nCCN No. AS002M0035-04: <color=#ffd34c>【附录-003】 影像记录#2</color>      ","DEU":"AEGIS 8 PBLIT-SICHERHEITSSEQUENZ: <color=#ffd34c>AKTIVIERT</color>     \\nADC-FAKTOR: <color=#ffd34c>ALPHA BESTÄTIGT</color>     \\nCCN-Nr. AS002M0035-04: <color=#ffd34c>【Anhang-003】 Videoaufzeichnung Nr.\xA02</color>      ","FRA":"AEGIS 8 PROTOCOLE DE SÉCURITÉ PBLIT\xA0: <color=#ffd34c>ACTIVÉ</color>     \\nFACTEUR CAD\xA0: <color=#ffd34c>ALPHA CONFIRMÉ</color>     \\nCCN No. AS002M0035-04\xA0: <color=#ffd34c>【Annexe-003】 Enregistrement vidéo #2</color>      "},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":"YOOJIN_ALT_NULL_NULL","text":{"KOREA":"으랏차아아아! 오늘 일도 이걸로 끝!","JPN":"よぉっしゃあああ！今日の仕事もこれにて終了だぜ！","ENG":"Haaaaa! That's it for today!","TWN":"啊啊啊啊啊啊啊啊啊啊啊！今天的工作結束了！"},"stage":{"bg":"OFFICE_LOCKERROOM","slots":{"L":null,"C":null,"R":{"char_id":"YOOJIN_ALT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L4_1","type":"dialog","speaker":"KIMSOBIN_ALT_NULL_NULL","text":{"KOREA":"다, 다들 고생했어......!","JPN":"み、みんなお疲れ様……！","ENG":"G-good work, everyone!","TWN":"各、各位辛苦了……！"},"stage":{"bg":"OFFICE_LOCKERROOM","slots":{"L":{"char_id":"KIMSOBIN_ALT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOJIN_ALT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"그러게. 요새는 이리저리 많이 불려 다니는 것 같아.","JPN":"そうね。最近、いろんなところに引っ張り出されてるわ。","ENG":"Indeed. It seems like we are being sent everywhere these days.","TWN":"是啊，最近好像一直被使喚來使喚去的。"},"stage":{"bg":"OFFICE_LOCKERROOM","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"YOOJIN_ALT_NULL_NULL","text":{"KOREA":"이 기세라면 정식 라이선스도 금방이지! 안 그래?","JPN":"この勢いなら正式ライセンスだってすぐに取れそうだな！そうだろ？","ENG":"We'll have our official licenses in no time! Right?","TWN":"照這個氣勢繼續下去，我們很快就會拿到正式執照了！對吧？"},"stage":{"bg":"OFFICE_LOCKERROOM","slots":{"L":{"char_id":"KIMSOBIN_ALT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOJIN_ALT_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L10_1","type":"dialog","speaker":"KIMSOBIN_ALT_NULL_NULL","text":{"KOREA":"으, 응!","JPN":"う、うん！","ENG":"Y-yeah!","TWN":"嗯、對！"},"stage":{"bg":"OFFICE_LOCKERROOM","slots":{"L":{"char_id":"KIMSOBIN_ALT_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"YOOJIN_ALT_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L12_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"라이선스를 구실로 부려먹어도 상도덕은 지켜 주면 좋겠는데......","JPN":"ライセンスをダシにしてコキ使うのはまあいいとして、商道徳に反することはよしてほしいわよね……","ENG":"Even if they are overworking us for the license, I wish they would keep their business morality...","TWN":"就算是用執照當藉口要我們苦工，至少也該遵守商業道德才對吧……"},"stage":{"bg":"OFFICE_LOCKERROOM","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"안 그래, 린?","JPN":"リンもそう思うでしょ？","ENG":"Don't you think so, Lin?","TWN":"對吧，琳？"},"stage":{"bg":"OFFICE_LOCKERROOM","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"......린?","JPN":"……リン？","ENG":"Lin?","TWN":"……琳？"},"stage":{"bg":"OFFICE_LOCKERROOM","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"XIAOLIN_ALT_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"OFFICE_LOCKERROOM","slots":{"L":null,"C":{"char_id":"XIAOLIN_ALT_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"왜 그래, 옷도 안 갈아입고? 무슨 일 있어?","JPN":"どうしたの？服も着替えてないじゃない。何かあったの？","ENG":"What's wrong? How come you're not changing? Did something happen?","TWN":"怎麼了，連衣服也不換？發生什麼事了嗎？"},"stage":{"bg":"OFFICE_LOCKERROOM","slots":{"L":{"char_id":"XIAOLIN_ALT_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"XIAOLIN_ALT_NULL_NULL","text":{"KOREA":"응?","JPN":"え？","ENG":"Huh?","TWN":"嗯？"},"stage":{"bg":"OFFICE_LOCKERROOM","slots":{"L":{"char_id":"XIAOLIN_ALT_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"XIAOLIN_ALT_NULL_NULL","text":{"KOREA":"아냐, 대장. 연구소에 다녀온 뒤로 어쩐지 계속 피곤해서.","JPN":"違うの、隊長。研究所に行ってから、何だか少し疲れてて。","ENG":"It's nothing, Cap. I'm just a bit tired after the trip to the lab.","TWN":"沒事，隊長。只是從研究所回來後，總覺得有點累。"},"stage":{"bg":"OFFICE_LOCKERROOM","slots":{"L":{"char_id":"XIAOLIN_ALT_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"XIAOLIN_ALT_NULL_NULL","text":{"KOREA":"먼저 숙소에 가 있어. 조금 쉬다가 금방 갈게.","JPN":"先に宿舎に帰ってて。私は少しだけ休んで行くから。","ENG":"Go on and head back home first. I'll catch up after getting some rest.","TWN":"你們先回宿舍吧，我稍微休息一下就過去。"},"stage":{"bg":"OFFICE_LOCKERROOM","slots":{"L":{"char_id":"XIAOLIN_ALT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"YOOJIN_ALT_NULL_NULL","text":{"KOREA":"연구소에 갔는데 피곤해? 너 운동 부족 아냐?","JPN":"研究所に行ったのに疲れたのか？お前、運動不足なんじゃねえの？","ENG":"You're tired from a trip to the lab? You should work out more.","TWN":"去了趟研究所後很累？妳這是運動不足吧？"},"stage":{"bg":"OFFICE_LOCKERROOM","slots":{"L":{"char_id":"KIMSOBIN_ALT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOJIN_ALT_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L26_1","type":"dialog","speaker":"KIMSOBIN_ALT_NULL_NULL","text":{"KOREA":"아하하...... 저기, 유진아. 린도 기분이 안 좋은데 그런 말은......","JPN":"あはは……えっと、シロコ。リンは調子がよくないみたいだし、からかったりするのは……","ENG":"Ah hah hah... Um, Eujin. I don't think you should say that when Lin's not feeling well...","TWN":"啊哈哈……那個，劉珍。琳也有心情不好的時候，那種話就不要……"},"stage":{"bg":"OFFICE_LOCKERROOM","slots":{"L":{"char_id":"KIMSOBIN_ALT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOJIN_ALT_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L28_1","type":"dialog","speaker":"XIAOLIN_ALT_NULL_NULL","text":{"KOREA":"......그럴지도 모르겠네.","JPN":"……そうかもしれない。","ENG":"That might be true.","TWN":"……也許是那樣沒錯。"},"stage":{"bg":"OFFICE_LOCKERROOM","slots":{"L":null,"C":{"char_id":"XIAOLIN_ALT_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}}]`);export{e as default};